insert into jst_team_appointment (
    team_no, contest_id, channel_id, team_name, appointment_date, session_code,
    total_persons, member_persons, extra_persons, extra_list_json, writeoff_persons,
    status, create_by, create_time, update_by, update_time, remark, del_flag
) values (
    #{team.teamNo}, #{team.contestId}, #{team.channelId}, #{team.teamName}, #{team.appointmentDate}, #{team.sessionCode},
    #{team.totalPersons}, #{team.memberPersons}, #{team.extraPersons}, #{team.extraListJson}, #{team.writeoffPersons},
    #{team.status}, #{team.createBy}, #{team.createTime}, #{team.updateBy}, #{team.updateTime}, #{team.remark}, #{team.delFlag}
)

insert into jst_team_appointment_member (
    team_appointment_id, user_id, participant_id, member_no, name_snapshot, mobile_snapshot,
    sub_order_id, writeoff_status, create_by, create_time, update_by, update_time, remark, del_flag
) values (
    #{member.teamAppointmentId}, #{member.userId}, #{member.participantId}, #{member.memberNo}, #{member.nameSnapshot},
    #{member.mobileSnapshot}, #{member.subOrderId}, #{member.writeoffStatus}, #{member.createBy}, #{member.createTime},
    #{member.updateBy}, #{member.updateTime}, #{member.remark}, #{member.delFlag}
)

mapper.select:
select ifnull(sum(t.total_persons), 0)
from jst_team_appointment t
where t.del_flag = '0'
  and t.contest_id = #{contestId}
  and t.appointment_date = #{appointmentDate}
  and t.session_code = #{sessionCode}
  and t.status in ('booked', 'partial_writeoff', 'fully_writeoff')

select count(1)
from jst_appointment_record ar
where ar.del_flag = '0'
  and ar.contest_id = #{contestId}
  and ar.participant_id = #{participantId}
  and ar.main_status in ('booked', 'partial_writeoff', 'fully_writeoff', 'partial_writeoff_ended')

select t.team_appointment_id as teamAppointmentId, t.team_no as teamNo, t.team_name as teamName, t.contest_id as contestId, c.contest_name as contestName, t.appointment_date as appointmentDate, t.session_code as sessionCode, t.total_persons as totalPersons, t.writeoff_persons as writeoffPersons, t.status as status from jst_team_appointment t left join jst_contest c on c.contest_id = t.contest_id and c.del_flag = '0' where t.del_flag = '0' and t.channel_id = #{channelId}
and t.contest_id = #{query.contestId}
and t.status = #{query.status}
and t.session_code = #{query.sessionCode}
and t.appointment_date = #{query.appointmentDate}
order by t.create_time desc, t.team_appointment_id desc

mapper.update:
update jst_team_appointment
set status = #{targetStatus},
    writeoff_persons = #{targetWriteoffPersons},
    update_by = #{updateBy},
    update_time = #{updateTime}
where team_appointment_id = #{teamAppointmentId}
  and status = #{expectedStatus}
  and writeoff_persons = #{expectedWriteoffPersons}
  and del_flag = '0'

update jst_team_appointment_member
set writeoff_status = #{targetStatus},
    update_by = #{updateBy},
    update_time = #{updateTime}
where team_appointment_id = #{teamAppointmentId}
  and participant_id = #{participantId}
  and writeoff_status = #{expectedStatus}
  and del_flag = '0'
